var numRabbits = function(answers) {
    const cnt = new Map();
    for (const a of answers) cnt.set(a, (cnt.get(a) || 0) + 1);
    let total = 0;
    for (const [k, c] of cnt) {
        const group = k + 1;
        const groups = Math.ceil(c / group);
        total += groups * group;
    }
    return total;
};
